import{_ as e,o as l,c as o,ai as t}from"./chunks/framework.CsYGeNYI.js";const S=JSON.parse('{"title":"设备发现 + 传输协议","description":"","frontmatter":{"read_when":["实现或更改 Bonjour 发现/广播","调整远程连接模式（直连 vs SSH）","设计远程节点的节点发现 + 配对"],"summary":"用于发现 Gateway 网关的节点发现和传输协议（Bonjour、Tailscale、SSH）","title":"设备发现 + 传输协议","x-i18n":{"generated_at":"2026-02-03T10:06:11Z","model":"claude-opus-4-5","provider":"pi","source_hash":"e12172c181515bfa6aab8625ed3fbc335b80ba92e2b516c02c6066aeeb9f884c","source_path":"gateway/discovery.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/discovery.md","filePath":"zh-CN/gateway/discovery.md","lastUpdated":null}'),i={name:"zh-CN/gateway/discovery.md"};function r(d,a,c,s,n,h){return l(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="设备发现-传输协议" tabindex="-1"><a class="header-anchor" href="#设备发现-传输协议">#</a> 设备发现 &amp; 传输协议</h1><p>OpenSoul 有两个表面上看起来相似的不同问题：</p><ol><li><strong>操作员远程控制</strong>：macOS 菜单栏应用控制运行在其他地方的 Gateway 网关。</li><li><strong>节点配对</strong>：iOS/Android（以及未来的节点）发现 Gateway 网关并安全配对。</li></ol><p>设计目标是将所有网络发现/广播保留在 <strong>Node Gateway 网关</strong>（<code>opensoul gateway</code>）中，并让客户端（mac 应用、iOS）作为消费者。</p><h2 id="术语" tabindex="-1"><a class="header-anchor" href="#术语">#</a> 术语</h2><ul><li><strong>Gateway 网关</strong>：一个长期运行的 Gateway 网关进程，拥有状态（会话、配对、节点注册表）并运行渠道。大多数设置每台主机使用一个；也可以进行隔离的多 Gateway 网关设置。</li><li><strong>Gateway 网关 WS（控制平面）</strong>：默认在 <code>127.0.0.1:18789</code> 上的 WebSocket 端点；可通过 <code>gateway.bind</code> 绑定到 LAN/tailnet。</li><li><strong>直连 WS 传输</strong>：面向 LAN/tailnet 的 Gateway 网关 WS 端点（无 SSH）。</li><li><strong>SSH 传输（回退）</strong>：通过 SSH 转发 <code>127.0.0.1:18789</code> 进行远程控制。</li><li><strong>旧版 TCP 桥接（已弃用/移除）</strong>：旧的节点传输（参见 <a href="/docs/gateway/bridge-protocol">桥接协议</a>）；不再用于发现广播。</li></ul><p>协议详情：</p><ul><li><a href="/docs/gateway/protocol">Gateway 网关协议</a></li><li><a href="/docs/gateway/bridge-protocol">桥接协议（旧版）</a></li></ul><h2 id="为什么我们同时保留-直连-和-ssh" tabindex="-1"><a class="header-anchor" href="#为什么我们同时保留-直连-和-ssh">#</a> 为什么我们同时保留&quot;直连&quot;和 SSH</h2><ul><li><strong>直连 WS</strong> 在同一网络和 tailnet 内提供最佳用户体验： <ul><li>通过 Bonjour 在 LAN 上自动发现</li><li>配对令牌 + ACL 由 Gateway 网关管理</li><li>无需 shell 访问；协议表面可保持紧凑和可审计</li></ul></li><li><strong>SSH</strong> 仍然是通用回退方案： <ul><li>只要你有 SSH 访问权限就能工作（即使跨越不相关的网络）</li><li>能应对多播/mDNS 问题</li><li>除 SSH 外无需新的入站端口</li></ul></li></ul><h2 id="发现输入-客户端如何了解-gateway-网关位置" tabindex="-1"><a class="header-anchor" href="#发现输入-客户端如何了解-gateway-网关位置">#</a> 发现输入（客户端如何了解 Gateway 网关位置）</h2><h3 id="_1-bonjour-mdns-仅限-lan" tabindex="-1"><a class="header-anchor" href="#_1-bonjour-mdns-仅限-lan">#</a> 1）Bonjour / mDNS（仅限 LAN）</h3><p>Bonjour 是尽力而为的，不会跨网络。它仅用于&quot;同一 LAN&quot;的便利性。</p><p>目标方向：</p><ul><li><strong>Gateway 网关</strong>通过 Bonjour 广播其 WS 端点。</li><li>客户端浏览并显示&quot;选择一个 Gateway 网关&quot;列表，然后存储选定的端点。</li></ul><p>故障排除和信标详情：<a href="/docs/gateway/bonjour">Bonjour</a>。</p><h4 id="服务信标详情" tabindex="-1"><a class="header-anchor" href="#服务信标详情">#</a> 服务信标详情</h4><ul><li>服务类型： <ul><li><code>_opensoul-gw._tcp</code>（Gateway 网关传输信标）</li></ul></li><li>TXT 键（非机密）： <ul><li><code>role=gateway</code></li><li><code>lanHost=&lt;hostname&gt;.local</code></li><li><code>sshPort=22</code>（或广播的端口）</li><li><code>gatewayPort=18789</code>（Gateway 网关 WS + HTTP）</li><li><code>gatewayTls=1</code>（仅当启用 TLS 时）</li><li><code>gatewayTlsSha256=&lt;sha256&gt;</code>（仅当启用 TLS 且指纹可用时）</li><li><code>canvasPort=18793</code>（默认画布主机端口；服务于 <code>/__opensoul__/canvas/</code>）</li><li><code>cliPath=&lt;path&gt;</code>（可选；可运行的 <code>opensoul</code> 入口点或二进制文件的绝对路径）</li><li><code>tailnetDns=&lt;magicdns&gt;</code>（可选提示；当 Tailscale 可用时自动检测）</li></ul></li></ul><p>禁用/覆盖：</p><ul><li><code>OPENSOUL_DISABLE_BONJOUR=1</code> 禁用广播。</li><li><code>~/.opensoul/opensoul.json</code> 中的 <code>gateway.bind</code> 控制 Gateway 网关绑定模式。</li><li><code>OPENSOUL_SSH_PORT</code> 覆盖 TXT 中广播的 SSH 端口（默认为 22）。</li><li><code>OPENSOUL_TAILNET_DNS</code> 发布 <code>tailnetDns</code> 提示（MagicDNS）。</li><li><code>OPENSOUL_CLI_PATH</code> 覆盖广播的 CLI 路径。</li></ul><h3 id="_2-tailnet-跨网络" tabindex="-1"><a class="header-anchor" href="#_2-tailnet-跨网络">#</a> 2）Tailnet（跨网络）</h3><p>对于伦敦/维也纳风格的设置，Bonjour 无法帮助。推荐的&quot;直连&quot;目标是：</p><ul><li>Tailscale MagicDNS 名称（首选）或稳定的 tailnet IP。</li></ul><p>如果 Gateway 网关能检测到它正在 Tailscale 下运行，它会发布 <code>tailnetDns</code> 作为客户端的可选提示（包括广域信标）。</p><h3 id="_3-手动-ssh-目标" tabindex="-1"><a class="header-anchor" href="#_3-手动-ssh-目标">#</a> 3）手动 / SSH 目标</h3><p>当没有直连路由（或直连被禁用）时，客户端始终可以通过 SSH 转发本地回环 Gateway 网关端口来连接。</p><p>参见 <a href="/docs/gateway/remote">远程访问</a>。</p><h2 id="传输选择-客户端策略" tabindex="-1"><a class="header-anchor" href="#传输选择-客户端策略">#</a> 传输选择（客户端策略）</h2><p>推荐的客户端行为：</p><ol><li>如果已配置且可达已配对的直连端点，使用它。</li><li>否则，如果 Bonjour 在 LAN 上找到 Gateway 网关，提供一键&quot;使用此 Gateway 网关&quot;选择并将其保存为直连端点。</li><li>否则，如果配置了 tailnet DNS/IP，尝试直连。</li><li>否则，回退到 SSH。</li></ol><h2 id="配对-认证-直连传输" tabindex="-1"><a class="header-anchor" href="#配对-认证-直连传输">#</a> 配对 + 认证（直连传输）</h2><p>Gateway 网关是节点/客户端准入的唯一权威来源。</p><ul><li>配对请求在 Gateway 网关中创建/批准/拒绝（参见 <a href="/docs/gateway/pairing">Gateway 网关配对</a>）。</li><li>Gateway 网关强制执行： <ul><li>认证（令牌 / 密钥对）</li><li>作用域/ACL（Gateway 网关不是每个方法的原始代理）</li><li>速率限制</li></ul></li></ul><h2 id="各组件职责" tabindex="-1"><a class="header-anchor" href="#各组件职责">#</a> 各组件职责</h2><ul><li><strong>Gateway 网关</strong>：广播发现信标，拥有配对决策权，并托管 WS 端点。</li><li><strong>macOS 应用</strong>：帮助你选择 Gateway 网关，显示配对提示，仅将 SSH 作为回退方案。</li><li><strong>iOS/Android 节点</strong>：将 Bonjour 浏览作为便利功能，连接到已配对的 Gateway 网关 WS。</li></ul>',35)])])}const g=e(i,[["render",r]]);export{S as __pageData,g as default};
